sql:
SELECT event_type, magnitude, event_time
FROM seismic_events
ORDER BY magnitude DESC;

SELECT AVG(magnitude) 
FROM seismic_events 
WHERE event_id IN ('the_event_ids_from_previous_step');

SELECT DISTINCT se.event_type
FROM seismic_events se
JOIN event_distances ed ON se.event_id = ed.event_id;

SELECT magnitude_id, magnitude_value, magnitude_type
FROM event_magnitudes
WHERE magnitude_value > (SELECT AVG(magnitude_value) FROM event_magnitudes);

SELECT u.user_id, u.user_name, u.email, u.organization
FROM users u
INNER JOIN seismic_events e ON u.user_name = e.source_mechanism;

external_knowledge:
- Magnitude of 6 or more signifies significant seismic activity that could cause noticeable damage; 
- The term 'Richter scale' is used metaphorically for magnitude measurement; 
- 'Secrets of the earth' refers to the geological information extracted from seismic events;
- 'Stewards of knowledge' metaphorically represents scientific observers, particularly those with the role of 'scientist'.

sql:
SELECT event_id, magnitude
FROM seismic_events
WHERE magnitude = (SELECT MAX(magnitude) FROM seismic_events);

SELECT e.event_id
FROM seismic_events e
WHERE e.data_source = 'Alice Johnson';

SELECT AVG(magnitude_value) AS average_magnitude
FROM event_magnitudes
WHERE magnitude_type = 'Richter';

SELECT *
FROM event_distances
WHERE distance_id = 1;
